#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_kernel(const T * __restrict__ mask,
                              const T * __restrict__ in,
                              T * __restrict__ out,
                              const int input_width,
                              const int mask_width)
{
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i >= input_width) return;

  int start = i - mask_width / 2;
  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    int idx = start + j;
    if (idx >= 0 && idx < input_width) {
      s += in[idx] * mask[j];
    }
  }
  out[i] = s;
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T *__restrict__ mask,
                                    const T *__restrict__ in,
                                    T *__restrict__ out,
                                    const int input_width,
                                    const int mask_width)
{
  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  if (i >= input_width) return;

  extern __shared__ T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];

  int n = mask_width / 2;

  // Load left halo
  int halo_left = (bid - 1) * dim + lid;
  if (lid >= dim - n) {
    int idx = lid - (dim - n);
    tile[idx] = (halo_left < 0 || halo_left >= input_width) ? 0 : in[halo_left];
  }

  // Load current element
  tile[n + lid] = in[i];

  // Load right halo
  int halo_right = (bid + 1) * dim + lid;
  if (lid < n) {
    int idx = lid + dim + n;
    tile[idx] = (halo_right >= input_width) ? 0 : in[halo_right];
  }

  __syncthreads();

  T s = 0;
  for (int j = 0; j < mask_width; j++) {
    s += tile[lid + j] * mask[j];
  }

  out[i] = s;
}

template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_caching_kernel(const T *__restrict__ mask,
                                            const T *__restrict__ in,
                                            T *__restrict__ out,
                                            const int input_width,
                                            const int mask_width)
{
  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  if (i >= input_width) return;

  extern __shared__ T tile[BLOCK_SIZE];
  tile[lid] = in[i];

  __syncthreads();

  int this_tile_start = bid * dim;
  int next_tile_start = (bid + 1) * dim;
  int start = i - (mask_width / 2);
  T s = 0;

  for (int j = 0; j < mask_width; j++) {
    int in_index = start + j;
    if (in_index >= 0 && in_index < input_width) {
      if (in_index >= this_tile_start && in_index < next_tile_start) {
        s += tile[lid + j - (mask_width / 2)] * mask[j];
      } else {
        s += in[in_index] * mask[j];
      }
    }
  }
  out[i] = s;
}

